from collections import defaultdict


class MapSum:
    def __init__(self):
        self.vals = {}
        self.prefix_sums = defaultdict(int)
    def insert(self, key, val):
        delta = val - self.vals.get(key, 0)
        self.vals[key] = val
        for i in range(1, len(key) + 1):
            self.prefix_sums[key[:i]] += delta
    def sum(self, prefix):
        return self.prefix_sums.get(prefix, 0)

