class MapSum {
    constructor() {
        this.vals = new Map();
        this.prefixSums = new Map();
    }
    insert(key, val) {
        const delta = val - (this.vals.get(key) || 0);
        this.vals.set(key, val);
        for (let i = 1; i <= key.length; i++) {
            const p = key.slice(0, i);
            this.prefixSums.set(p, (this.prefixSums.get(p) || 0) + delta);
        }
    }
    sum(prefix) {
        return this.prefixSums.get(prefix) || 0;
    }
}
